	var size: Int = (maxN + 1).to_int
	fact = array[size]
	invFact = array[size]

	fact[0] = 1
	for i in 1..size {
		fact[i] = (fact[i-1] * i) % MOD
	}

	// Compute invFact[maxN] first
	invFact[size-1] = modInverse(fact[size-1])

	// Compute remaining inverse factorials iteratively
	for i in (size-2).down_to(0) {
		invFact[i] = (invFact[i+1] * (i+1)) % MOD
	}
